function triggerFlash() {
  const f = document.getElementById('ar-flash');
  f.classList.remove('flash');
  void f.offsetWidth;
  f.classList.add('flash');
}

function renderGhostSilhouettes() {
  const ov = document.getElementById('ar-ghost-ov');
  ov.innerHTML = '';
  const W = window.innerWidth, H = window.innerHeight;
  const positions = [0.12, 0.3, 0.55, 0.75, 0.88];
  const shapes = [...GHOST_SHAPES, GHOST_SHAPES[0], GHOST_SHAPES[2]];
  positions.forEach((xRatio, i) => {
    const shape = shapes[i % shapes.length];
    const x = W * xRatio;
    const scale = 0.7 + Math.random() * 0.6;
    const yOffset = H * 0.05 + Math.random() * (H * 0.1);
    const wrapper = document.createElement('div');
    wrapper.className = 'ghost-silhouette';
    wrapper.style.cssText = `left:${x}px; bottom:${yOffset}px; transform:translateX(-50%) scale(${scale.toFixed(2)}); transform-origin: bottom center; animation-delay:${(i*0.4).toFixed(1)}s`;
    wrapper.innerHTML = shape.svg;
    ov.appendChild(wrapper);
    const lbl = document.createElement('div');
    lbl.className = 'ghost-label';
    lbl.textContent = shape.label;
    lbl.style.cssText = `left:${x}px; bottom:${yOffset + 10 + (shape.svg.match(/height="(\d+)"/)?.[1]||100)*scale}px; animation-delay:${(i*0.4+0.2).toFixed(1)}s`;
    ov.appendChild(lbl);
  });
}

function startGhostAudio() {
  if (ghostAudio) return;
  try {
    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    const master = ctx.createGain(); master.gain.value = 0.18; master.connect(ctx.destination);
    function addBell(delay) {
      setTimeout(() => {
        if (!ghostMode) return;
        const osc = ctx.createOscillator();
        const g = ctx.createGain();
        osc.type = 'sine'; osc.frequency.value = 440 + Math.random()*120;
        g.gain.setValueAtTime(0.3, ctx.currentTime);
        g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 3);
        osc.connect(g); g.connect(master);
        osc.start(); osc.stop(ctx.currentTime + 3);
        if (ghostMode) addBell(4000 + Math.random()*8000);
      }, delay);
    }
    function addWind() {
      const buf = ctx.createBuffer(1, ctx.sampleRate * 4, ctx.sampleRate);
      const d = buf.getChannelData(0);
      for (let i=0; i<d.length; i++) d[i] = (Math.random()*2-1)*0.15;
      const src = ctx.createBufferSource();
      const filt = ctx.createBiquadFilter(); filt.type='lowpass'; filt.frequency.value=400;
      const g = ctx.createGain(); g.gain.value=0.4;
      src.buffer=buf; src.loop=true;
      src.connect(filt); filt.connect(g); g.connect(master);
      src.start();
      ghostAudio = { ctx, src, stop: ()=>{ try{src.stop(); ctx.close();}catch(e){} } };
    }
    addWind();
    addBell(1000); addBell(5000); addBell(9000);
  } catch(e) {}
}

function stopGhostAudio() {
  if (ghostAudio) { ghostAudio.stop(); ghostAudio = null; }
}

function toggleGhostMode() {
  ghostMode = !ghostMode;
  const btn = document.getElementById('ar-ghost-btn');
  const video = document.getElementById('ar-video');
  const grain = document.getElementById('ar-grain');
  const vignette = document.getElementById('ar-vignette');
  const scratches = document.getElementById('ar-scratches');
  const ghostOv = document.getElementById('ar-ghost-ov');
  const banner = document.getElementById('ar-epoch-banner');
  triggerFlash();
  setTimeout(() => {
    if (ghostMode) {
      video.classList.add('ghost-mode');
      grain.classList.add('on');
      vignette.classList.add('on');
      scratches.classList.add('on');
      ghostOv.classList.add('on');
      banner.classList.add('on');
      btn.classList.add('active');
      btn.innerHTML = '<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><polyline points="12,6 12,12 15,15"/></svg> XIIIe siècle';
      renderGhostSilhouettes();
      startGhostAudio();
      renderHistoryPhotos();
    } else {
      video.classList.remove('ghost-mode');
      grain.classList.remove('on');
      vignette.classList.remove('on');
      scratches.classList.remove('on');
      ghostOv.classList.remove('on');
      banner.classList.remove('on');
      btn.classList.remove('active');
      btn.innerHTML = '<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><polyline points="12,6 12,12 15,15"/><path d="M2 12h2M20 12h2M12 2v2M12 20v2" stroke-width="1.5" opacity="0.5"/></svg> Mode Histoire';
      stopGhostAudio();
    }
  }, 80);
}
let arHeading = 0;
let immParticleTimer = null;
let currentImmPlace = null;

// ─── MAP INIT ─────────────────────────────────────────────────────────────
function initMap() {
  map = L.map('map', {
    center: [43.9620, 4.7990],
    zoom: 15, zoomControl: false,
    attributionControl: false,
  });
  L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', {
    maxZoom: 19,
  }).addTo(map);
  L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager_only_labels/{z}/{x}/{y}{r}.png', {
    maxZoom: 19, opacity: 0.85,
  }).addTo(map);
  L.control.zoom({ position: 'topright' }).addTo(map);

  // Filter bar
  buildFilterBar();
  // Markers tourisme
  initTourismeMarkers();
  initCommerceMarkers();
  initEvenementsMarkers();
  switchSection('tourisme');
  // GPS en arrière-plan discret
  if (navigator.geolocation) navigator.geolocation.getCurrentPosition(p => { userLat=p.coords.latitude; userLng=p.coords.longitude; }, ()=>{}, {enableHighAccuracy:true});
}

function makePinSVG(color) {
  const id = 'f' + color.replace('#','');
  return `<svg xmlns="http://www.w3.org/2000/svg" width="28" height="40" viewBox="0 0 28 40">
  <defs><filter id="${id}" x="-40%" y="-20%" width="180%" height="160%">
    <feDropShadow dx="0" dy="3" stdDeviation="3" flood-color="rgba(0,0,0,0.3)" flood-opacity="1"/>
  </filter></defs>
  <path d="M14 1C7.925 1 3 5.925 3 12c0 7.2 11 27 11 27S25 19.2 25 12c0-6.075-4.925-11-11-11z" fill="${color}" filter="url(#${id})"/>
  <circle cx="14" cy="12" r="5.5" fill="white" opacity="0.95"/>
  <circle cx="14" cy="12" r="2.5" fill="${color}"/>
</svg>`;
}

function buildFilterBar() {
  const bar = document.getElementById('filter-bar');
  bar.innerHTML = '';
  const all = Object.keys(CATS);
  const items = [{ key:'all', label:'Tout', color:'#0f1923' }, ...all.map(k => ({ key:k, label:CATS[k].label, color:CATS[k].color }))];
  items.forEach(item => {
    const btn = document.createElement('button');
    btn.className = 'fp' + (item.key === activeFilter ? ' active' : '');
    btn.innerHTML = `<span class="fdot" style="background:${item.color}"></span>${item.label}`;
    btn.onclick = () => { activeFilter = item.key; buildFilterBar(); filterMarkers(); };
    bar.appendChild(btn);
  });
}

function filterMarkers() {
  tourismeMarkers.forEach(({ place, marker }) => {
    if (activeFilter === 'all' || place.cat === activeFilter) {
      marker.addTo(map);
    } else {
      map.removeLayer(marker);
    }
  });
}

function initTourismeMarkers() {
  PLACES.forEach(place => {
    const col = CATS[place.cat]?.color || '#1a73e8';
    const icon = L.divIcon({
      html: makePinSVG(col),
      className: '', iconSize: [28, 40], iconAnchor: [14, 40], popupAnchor: [0, -44],
    });
    const marker = L.marker([place.lat, place.lng], { icon }).addTo(map);
    marker.on('click', () => openMiniPopup(place));
    tourismeMarkers.push({ place, marker });
  });
}

function initCommerceMarkers() {
  COMMERCANTS.forEach(c => {
    const col = CATS_COMMERCE[c.cat]?.color || '#1a73e8';
    const icon = L.divIcon({
      html: makePinSVG(col),
      className: '', iconSize: [28,40], iconAnchor: [14,40],
    });
    const m = L.marker([c.lat, c.lng], { icon });
    m.on('click', () => openCommercantPopup(c));
    commerceMarkers.push(m);
  });
}

function switchSection(section) {
  currentSection = section;
  document.getElementById('nav-tourisme').classList.toggle('active', section === 'tourisme');
  document.getElementById('nav-commerce').classList.toggle('active', section === 'commerce');
  document.getElementById('nav-evenements').classList.toggle('active', section === 'evenements');
  const fb = document.getElementById('filter-bar');
  closeCustomPopup();

  if (section === 'tourisme') {
    fb.style.display = 'flex';
    tourismeMarkers.forEach(({ marker }) => marker.addTo(map));
    commerceMarkers.forEach(m => map.removeLayer(m));
    evenementsMarkers.forEach(m => map.removeLayer(m));
  } else if (section === 'commerce') {
    fb.style.display = 'none';
    tourismeMarkers.forEach(({ marker }) => map.removeLayer(marker));
    commerceMarkers.forEach(m => m.addTo(map));
    evenementsMarkers.forEach(m => map.removeLayer(m));
  } else {
    fb.style.display = 'none';
    tourismeMarkers.forEach(({ marker }) => map.removeLayer(marker));
    commerceMarkers.forEach(m => map.removeLayer(m));
    evenementsMarkers.forEach(m => m.addTo(map));
  }
}

