function openCustomPopup(html) {
  const card = document.getElementById('popup-card');
  const container = document.getElementById('popup-container');
  card.innerHTML = html;
  container.classList.add('active');
  container.onclick = e => { if (!card.contains(e.target)) closeCustomPopup(); };
  requestAnimationFrame(() => card.classList.add('visible'));
  setMapBlur(true);
}
function closeCustomPopup() {
  const card = document.getElementById('popup-card');
  const container = document.getElementById('popup-container');
  card.classList.remove('visible');
  setTimeout(() => { container.classList.remove('active'); card.innerHTML = ''; }, 250);
  setMapBlur(false);
}
function setMapBlur(on) {
  document.getElementById('map').classList.toggle('map-blur', on);
}

// ─── TYPEWRITER ───────────────────────────────────────────────────────────
let typewriterTimer = null;
function typewrite(text, speed = 28) {
  const el = document.getElementById('imm-narration-text');
  const cursor = document.getElementById('imm-cursor');
  if (!el || !cursor) return;
  if (typewriterTimer) clearInterval(typewriterTimer);
  el.textContent = '';
  cursor.classList.remove('done');
  let i = 0;
  typewriterTimer = setInterval(() => {
    if (i < text.length) {
      el.textContent += text[i];
      i++;
    } else {
      clearInterval(typewriterTimer);
      typewriterTimer = null;
      setTimeout(() => cursor.classList.add('done'), 800);
    }
  }, speed);
}

// ─── EXPÉRIENCE IMMERSIVE ─────────────────────────────────────────────────
function openImmersive(placeId) {
  const place = PLACES.find(p => p.id === placeId);
  if (!place) return;
  currentImmPlace = place;

  // CRITIQUE : créer l'audio ici directement dans le clic utilisateur
  closeCustomPopup();

  const overlay = document.getElementById('imm-overlay');
  const theme = CAT_THEMES[place.cat] || CAT_THEMES.monument;

  // Reset
  overlay.classList.remove('ready');
  overlay.classList.add('bars-open');
  if (typewriterTimer) { clearInterval(typewriterTimer); typewriterTimer = null; }
  const narEl = document.getElementById('imm-narration-text');
  if (narEl) narEl.textContent = '';
  const cursor = document.getElementById('imm-cursor');
  if (cursor) cursor.classList.remove('done');

  // Fond
  const bg = document.getElementById('imm-bg');
  bg.style.backgroundImage = `url('${place.bg}')`;
  bg.classList.remove('ready');

  // Teinte époque
  const tint = document.getElementById('imm-tint');
  tint.style.background = theme.tint;
  tint.classList.remove('ready');

  // Une seule ligne : tout le thème via CSS variables sur l'overlay
  overlay.style.setProperty('--acc',     theme.accentLight);
  overlay.style.setProperty('--acc-mid', theme.accentLight + '33');
  overlay.style.setProperty('--acc-bg',  theme.badgeBg);

  // Contenu texte
  document.getElementById('imm-era-badge').textContent = place.eraTxt;
  document.getElementById('imm-title').textContent = place.name;
  document.getElementById('imm-subtitle').textContent = place.subtitle;
  document.getElementById('imm-stat-age').textContent = place.century;
  document.getElementById('imm-stat-cat').textContent = place.catLabel;

  // Bouton naviguer — couleur du thème
  const btn = document.getElementById('imm-navigate-btn');
  if (btn) btn.style.background = theme.btnGrad;

  // Distance
  const dist = calcDist(userLat, userLng, place.lat, place.lng);
  document.getElementById('imm-stat-dist').textContent = dist < 1000 ? Math.round(dist) + 'm' : (dist/1000).toFixed(1) + 'km';

  // Panneau détail
  buildDetailPanel(place, theme);

  // Bouton naviguer
  document.getElementById('imm-navigate-btn').onclick = () => {
    closeImmersive();
    startRoute(place.lat, place.lng);
  };

  // Afficher
  overlay.style.display = 'flex';

  // Séquence cinématographique
  setTimeout(() => {
    bg.classList.add('ready');
    tint.classList.add('ready');
  }, 100);

  setTimeout(() => {
    overlay.classList.remove('bars-open');
  }, 400);

  setTimeout(() => {
    overlay.classList.add('ready');
    startParticles(theme.particles);
    // Lancer la machine à écrire après que tout soit visible
    setTimeout(() => typewrite(place.narration, 22), 300);
  }, 600);
}

function buildDetailPanel(place, theme) {
  const inner = document.getElementById('imm-detail-inner');
  const tlHtml = place.timeline.map(t => `
    <div class="imm-tl-item">
      <div class="imm-tl-dot"></div>
      <span class="imm-tl-year">${t.year}</span>
      <span class="imm-tl-text">${t.text}</span>
    </div>`).join('');

  inner.innerHTML = `
    <div class="imm-detail-section">
      <h4>Histoire</h4>
      <p>${place.history}</p>
    </div>
    <div class="imm-detail-section">
      <h4>Chronologie</h4>
      <div class="imm-timeline">${tlHtml}</div>
    </div>
    <div class="imm-detail-section">
      <h4>Le saviez-vous ?</h4>
      <p>${place.anecdote}</p>
    </div>
  `;

  // Les couleurs sont héritées via les CSS variables --acc sur #imm-overlay

  // Clic "En savoir plus" + swipe pour ouvrir le panneau
  const detail = document.getElementById('imm-detail');
  const scrollHint = document.getElementById('imm-scroll');
  if (scrollHint) scrollHint.onclick = () => detail.classList.toggle('open');

  // Swipe haut/bas sur le contenu
  const content = document.getElementById('imm-content');
  let startY = 0;
  // On remplace les listeners en clonant le nœud
  const newContent = content.cloneNode(false);
  while (content.firstChild) newContent.appendChild(content.firstChild);
  content.parentNode.replaceChild(newContent, content);
  newContent.addEventListener('touchstart', e => { startY = e.touches[0].clientY; }, { passive: true });
  newContent.addEventListener('touchend', e => {
    const dy = startY - e.changedTouches[0].clientY;
    if (dy > 40) detail.classList.add('open');
    if (dy < -40) detail.classList.remove('open');
  }, { passive: true });
}

function closeImmersive() {
  const overlay = document.getElementById('imm-overlay');
  overlay.classList.remove('ready');
  overlay.classList.add('bars-open');
  stopParticles();
  if (typewriterTimer) { clearInterval(typewriterTimer); typewriterTimer = null; }

  setTimeout(() => {
    overlay.style.display = 'none';
    overlay.classList.remove('bars-open');
    document.getElementById('imm-detail').classList.remove('open');
    document.getElementById('imm-bg').classList.remove('ready');
    document.getElementById('imm-tint').classList.remove('ready');
  }, 700);
}

// ─── PARTICULES ───────────────────────────────────────────────────────────
function startParticles(color) {
  stopParticles();
  const container = document.getElementById('imm-particles');
  container.innerHTML = '';

  function addParticle() {
    const p = document.createElement('div');
    p.className = 'imm-particle';
    const size = Math.random() * 4 + 1;
    const left = Math.random() * 100;
    const duration = Math.random() * 8 + 6;
    const delay = Math.random() * 4;
    p.style.cssText = `
      width:${size}px; height:${size}px;
      left:${left}%;
      bottom: -10px;
      background: ${color};
      animation: float-up ${duration}s ${delay}s linear infinite;
    `;
    container.appendChild(p);
    if (container.children.length > 30) container.removeChild(container.children[0]);
  }

  for (let i = 0; i < 20; i++) addParticle();
  immParticleTimer = setInterval(() => addParticle(), 400);
}
function stopParticles() {
  if (immParticleTimer) { clearInterval(immParticleTimer); immParticleTimer = null; }
  document.getElementById('imm-particles').innerHTML = '';
}

// ─── CALCUL DISTANCE ──────────────────────────────────────────────────────
function calcDist(lat1, lng1, lat2, lng2) {
  const R = 6371000;
  const dLat = (lat2-lat1)*Math.PI/180;
  const dLng = (lng2-lng1)*Math.PI/180;
  const a = Math.sin(dLat/2)**2 + Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLng/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

// ─── AR ───────────────────────────────────────────────────────────────────

// ─── GPS WATCH ────────────────────────────────────────────────────────────
let gpsWatchId = null;
let navActive = false;
let navDestLat = null, navDestLng = null;
let navRouteLayer = null;
let navUserMarker = null;
let selectedRadarPlace = null;

function startGPSWatch() {
  if (gpsWatchId) return;
  if (!navigator.geolocation) return;
  gpsWatchId = navigator.geolocation.watchPosition(pos => {
    userLat = pos.coords.latitude;
    userLng = pos.coords.longitude;
    if (userMarker) userMarker.setLatLng([userLat, userLng]);
    if (navActive) updateNavigation();
    if (arActive) updateARDistances();
    if (ghostMode) renderHistoryPhotos();
    if (document.getElementById('radar-view').classList.contains('on')) drawRadar();
  }, null, { enableHighAccuracy: true, maximumAge: 2000 });
}

function stopGPSWatch() {
  if (gpsWatchId) { navigator.geolocation.clearWatch(gpsWatchId); gpsWatchId = null; }
}

// ─── AR AMÉLIORÉ ──────────────────────────────────────────────────────────
function startAR() {
  if (!navigator.mediaDevices?.getUserMedia) { showToast('Caméra non disponible'); return; }
  document.getElementById('ar-view').classList.add('on');
  document.getElementById('nav-ar').classList.add('active');
  navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment', width:{ideal:1920}, height:{ideal:1080} }, audio: false })
    .then(stream => {
      arStream = stream;
      document.getElementById('ar-video').srcObject = stream;
      arActive = true;
      startGPSWatch();
      renderARPins();
    })
    .catch(() => showToast('Accès caméra refusé'));
}
